const functions = require('@google-cloud/functions-framework');
const { BigQuery } = require('@google-cloud/bigquery');

const bigquery = new BigQuery();

// Cloud Function with maximum resource allocation for large dataset processing
// Deploy with: gcloud functions deploy processLargeDataset --runtime nodejs18 --trigger-http --memory 8192MB --timeout 540s --allow-unauthenticated
functions.http('processLargeDataset', async (req, res) => {
  const startTime = Date.now();
  const processingResults = {
    status: 'started',
    startTime: new Date().toISOString(),
    stages: [],
    errors: [],
    memoryUsage: {}
  };

  try {
    // Log initial memory usage
    const initialMemory = process.memoryUsage();
    processingResults.memoryUsage.initial = {
      heapUsed: `${(initialMemory.heapUsed / 1024 / 1024).toFixed(2)} MB`,
      heapTotal: `${(initialMemory.heapTotal / 1024 / 1024).toFixed(2)} MB`,
      rss: `${(initialMemory.rss / 1024 / 1024).toFixed(2)} MB`
    };

    // Extract parameters from request
    const {
      datasetId = 'my_dataset',
      sourceTable = 'raw_data',
      destinationTable = 'aggregated_results',
      dateRange = {},
      aggregationType = 'full',
      customQuery = null,
      batchSize = 100000
    } = req.body || {};

    const startDate = dateRange.start || '2020-01-01';
    const endDate = dateRange.end || new Date().toISOString().split('T')[0];

    console.log(`Processing dataset: ${datasetId}.${sourceTable}`);
    console.log(`Date range: ${startDate} to ${endDate}`);
    console.log(`Aggregation type: ${aggregationType}`);

    // Stage 1: Validate dataset and table existence
    processingResults.stages.push({ name: 'validation', status: 'in_progress' });
    
    const dataset = bigquery.dataset(datasetId);
    const [datasetExists] = await dataset.exists();
    if (!datasetExists) {
      throw new Error(`Dataset ${datasetId} does not exist`);
    }

    const table = dataset.table(sourceTable);
    const [tableExists] = await table.exists();
    if (!tableExists) {
      throw new Error(`Table ${sourceTable} does not exist in dataset ${datasetId}`);
    }

    const [metadata] = await table.getMetadata();
    const rowCount = parseInt(metadata.numRows, 10);
    const sizeBytes = parseInt(metadata.numBytes, 10);
    
    processingResults.stages[0] = {
      name: 'validation',
      status: 'completed',
      details: {
        rowCount,
        sizeGB: (sizeBytes / (1024 * 1024 * 1024)).toFixed(2),
        schema: metadata.schema.fields.map(f => ({ name: f.name, type: f.type }))
      }
    };

    console.log(`Source table has ${rowCount} rows (${(sizeBytes / (1024 * 1024 * 1024)).toFixed(2)} GB)`);

    // Stage 2: Run aggregation queries
    processingResults.stages.push({ name: 'aggregation', status: 'in_progress' });

    let aggregationQueries = [];

    if (customQuery) {
      aggregationQueries.push({
        name: 'custom_aggregation',
        query: customQuery
      });
    } else {
      // Build comprehensive aggregation queries based on type
      aggregationQueries = buildAggregationQueries(datasetId, sourceTable, startDate, endDate, aggregationType);
    }

    const aggregationResults = [];
    
    for (let i = 0; i < aggregationQueries.length; i++) {
      const queryConfig = aggregationQueries[i];
      console.log(`Running aggregation query ${i + 1}/${aggregationQueries.length}: ${queryConfig.name}`);

      const elapsedSeconds = (Date.now() - startTime) / 1000;
      if (elapsedSeconds > 480) {
        console.warn(`Approaching timeout limit (${elapsedSeconds}s elapsed). Processing remaining queries with priority.`);
      }

      try {
        const [job] = await bigquery.createQueryJob({
          query: queryConfig.query,
          location: 'US',
          maximumBytesBilled: '100000000000', // 100GB limit per query
          useLegacySql: false,
          jobTimeoutMs: 300000, // 5 minutes per query
          priority: 'INTERACTIVE'
        });

        console.log(`Job ${job.id} started for query: ${queryConfig.name}`);

        const [rows] = await job.getQueryResults({
          maxResults: batchSize,
          autoPaginate: true
        });

        const [jobMetadata] = await job.getMetadata();
        const queryStats = jobMetadata.statistics.query;

        aggregationResults.push({
          name: queryConfig.name,
          rowsReturned: rows.length,
          totalBytesProcessed: queryStats.totalBytesProcessed,
          totalBytesBilled: queryStats.totalBytesBilled,
          cacheHit: queryStats.cacheHit,
          data: rows.slice(0, 100) // Include first 100 rows in response
        });

        console.log(`Query ${queryConfig.name} completed: ${rows.length} rows, ${(parseInt(queryStats.totalBytesProcessed) / (1024 * 1024 * 1024)).toFixed(2)} GB processed`);

      } catch (queryError) {
        console.error(`Error in query ${queryConfig.name}:`, queryError.message);
        processingResults.errors.push({
          query: queryConfig.name,
          error: queryError.message
        });
        // Continue processing remaining queries
      }
    }

    processingResults.stages[1] = {
      name: 'aggregation',
      status: 'completed',
      queriesRun: aggregationQueries.length,
      queriesSucceeded: aggregationResults.length,
      queriesFailed: processingResults.errors.length,
      results: aggregationResults
    };

    // Stage 3: Store aggregated results back to BigQuery
    processingResults.stages.push({ name: 'store_results', status: 'in_progress' });

    if (aggregationResults.length > 0) {
      const combinedResults = aggregationResults.flatMap(result => 
        result.data.map(row => ({
          ...row,
          aggregation_name: result.name,
          processed_at: new Date().toISOString(),
          source_table: `${datasetId}.${sourceTable}`,
          date_range_start: startDate,
          date_range_end: endDate
        }))
      );

      if (combinedResults.length > 0) {
        // Process in batches to handle large result sets
        const totalBatches = Math.ceil(combinedResults.length / batchSize);
        let totalInserted = 0;

        for (let batch = 0; batch < totalBatches; batch++) {
          const batchData = combinedResults.slice(batch * batchSize, (batch + 1) * batchSize);
          
          try {
            const destTable = dataset.table(destinationTable);
            const [destExists] = await destTable.exists();

            if (!destExists) {
              // Create destination table with auto-detected schema
              const insertQuery = `
                CREATE TABLE IF NOT EXISTS \`${datasetId}.${destinationTable}\` AS
                SELECT * FROM UNNEST(@rows)
              `;
              console.log(`Creating destination table: ${destinationTable}`);
            }

            await destTable.insert(batchData, {
              skipInvalidRows: true,
              ignoreUnknownValues: true,
              createInsertId: true
            });

            totalInserted += batchData.length;
            console.log(`Batch ${batch + 1}/${totalBatches}: Inserted ${batchData.length} rows`);

          } catch (insertError) {
            if (insertError.name === 'PartialFailureError') {
              const failedRows = insertError.errors.length;
              totalInserted += (batchData.length - failedRows);
              console.warn(`Batch ${batch + 1}: ${failedRows} rows failed to insert`);
              processingResults.errors.push({
                stage: 'insert',
                batch: batch + 1,
                failedRows,
                sampleErrors: insertError.errors.slice(0, 5).map(e => e.errors)
              });
            } else {
              // Try using a load job as fallback for large batches
              console.warn(`Batch insert failed, attempting query-based insert: ${insertError.message}`);
              try {
                const insertQuery = `
                  INSERT INTO \`${datasetId}.${destinationTable}\`
                  SELECT * FROM UNNEST(?)
                `;
                processingResults.errors.push({
                  stage: 'insert_fallback',
                  batch: batch + 1,
                  error: insertError.message
                });
              } catch (fallbackError) {
                processingResults.errors.push({
                  stage: 'insert_fallback_failed',
                  batch: batch + 1,
                  error: fallbackError.message
                });
              }
            }
          }
        }

        processingResults.stages[2] = {
          name: 'store_results',
          status: 'completed',
          totalRowsInserted: totalInserted,
          destinationTable: `${datasetId}.${destinationTable}`
        };
      } else {
        processingResults.stages[2] = {
          name: 'store_results',
          status: 'skipped',
          reason: 'No data to store'
        };
      }
    }

    // Stage 4: Run summary statistics
    processingResults.stages.push({ name: 'summary_statistics', status: 'in_progress' });

    try {
      const summaryQuery = `
        SELECT
          COUNT(*) as total_records,
          COUNT(DISTINCT aggregation_name) as unique_aggregations,
          MIN(processed_at) as earliest_processing,
          MAX(processed_at) as latest_processing
        FROM \`${datasetId}.${destinationTable}\`
        WHERE processed_at >= TIMESTAMP('${new Date().toISOString().split('T')[0]}')
      `;

      const [summaryJob] = await bigquery.createQueryJob({
        query: summaryQuery,
        useLegacySql: false
      });

      const [summaryRows] = await summaryJob.getQueryResults();

      processingResults.stages[3] = {
        name: 'summary_statistics',
        status: 'completed',
        summary: summaryRows[0] || {}
      };
    } catch (summaryError) {
      processingResults.stages[3] = {
        name: 'summary_statistics',
        status: 'failed',
        error: summaryError.message
      };
    }

    // Final memory usage
    const finalMemory = process.memoryUsage();
    processingResults.memoryUsage.final = {
      heapUsed: `${(finalMemory.heapUsed / 1024 / 1024).toFixed(2)} MB`,
      heapTotal: `${(finalMemory.heapTotal / 1024 / 1024).toFixed(2)} MB`,
      rss: `${(finalMemory.rss / 1024 / 1024).toFixed(2)} MB`
    };

    const totalDuration = (Date.now() - startTime) / 1000;
    processingResults.status = 'completed';
    processingResults.endTime = new Date().toISOString();
    processingResults.totalDurationSeconds = totalDuration.toFixed(2);
    processingResults.totalErrors = processingResults.errors.length;

    console.log(`Processing completed in ${totalDuration.toFixed(2)} seconds with ${processingResults.errors.length} errors`);

    const statusCode = processingResults.errors.length > 0 ? 207 : 200;
    res.status(statusCode).json(processingResults);

  } catch (error) {
    const totalDuration = (Date.now() - startTime) / 1000;
    
    console.error('Fatal error during processing:', error);

    const finalMemory = process.memoryUsage();
    processingResults.memoryUsage.final = {
      heapUsed: `${(finalMemory.heapUsed / 1024 / 1024).toFixed(2)} MB`,
      heapTotal: `${(finalMemory.heapTotal / 1024 / 1024).toFixed(2)} MB`,
      rss: `${(finalMemory.rss / 1024 / 1024).toFixed(2)} MB`
    };

    processingResults.status = 'failed';
    processingResults.endTime = new Date().toISOString();
    processingResults.totalDurationSeconds = totalDuration.toFixed(2);
    processingResults.fatalError = {
      message: error.message,
      stack: error.stack
    };

    res.status(500).json(processingResults);
  }
});

/**
 * Build aggregation queries based on aggregation type
 */
function buildAggregationQueries(datasetId, sourceTable, startDate, endDate, aggregationType) {
  const fullTableRef = `\`${datasetId}.${sourceTable}\``;
  const queries = [];

  // Daily aggregation
  queries.push({
    name: 'daily_aggregation',
    query: `
      SELECT
        DATE(created_at) as aggregation_date,
        COUNT(*) as record_count,
        COUNT(DISTINCT user_id) as unique_users,
        SUM(CAST(amount AS FLOAT64)) as total_amount,
        AVG(CAST(amount AS FLOAT64)) as avg_amount,
        MIN(CAST(amount AS FLOAT64)) as min_amount,
        MAX(CAST(amount AS FLOAT64)) as max_amount,
        STDDEV(CAST(amount AS FLOAT64)) as stddev_amount,
        APPROX_QUANTILES(CAST(amount AS FLOAT64), 100)[OFFSET(50)] as median_amount,
        APPROX_QUANTILES(CAST(amount AS FLOAT64), 100)[OFFSET(95)] as p95_amount,
        APPROX_QUANTILES(CAST(amount AS FLOAT64), 100)[OFFSET(99)] as p99_amount
      FROM ${fullTableRef}
      WHERE DATE(created_at) BETWEEN '${startDate}' AND '${endDate}'
      GROUP BY aggregation_date
      ORDER BY aggregation_date
    `
  });

  if (aggregationType === 'full' || aggregationType === 'categorical') {
    // Category-based aggregation
    queries.push({
      name: 'category_aggregation',
      query: `
        SELECT
          category,
          COUNT(*) as record_count,
          COUNT(DISTINCT user_id) as unique_users,
          SUM(CAST(amount AS FLOAT64)) as total_amount,
          AVG(CAST(amount AS FLOAT64)) as avg_amount,
          STDDEV(CAST(amount AS FLOAT64)) as stddev_amount,
          APPROX_QUANTILES(CAST(amount AS FLOAT64), 100)[OFFSET(50)] as median_amount
        FROM ${fullTableRef}
        WHERE DATE(created_at) BETWEEN '${startDate}' AND '${endDate}'
        GROUP BY category
        ORDER BY total_amount DESC
      `
    });

    // Cross-dimensional aggregation
    queries.push({
      name: 'cross_dimensional_aggregation',
      query: `
        SELECT
          DATE_TRUNC(DATE(created_at), MONTH) as month,
          category,
          region,
          COUNT(*) as record_count,
          COUNT(DISTINCT user_id) as unique_users,
          SUM(CAST(amount AS FLOAT64)) as total_amount,
          AVG(CAST(amount AS FLOAT64)) as avg_amount
        FROM ${fullTableRef}
        WHERE DATE(created_at) BETWEEN '${startDate}' AND '${endDate}'
        GROUP BY month, category, region
        ORDER BY month, total_amount DESC
      `
    });
  }

  if (aggregationType === 'full' || aggregationType === 'user_analysis') {
    // User-level aggregation
    queries.push({
      name: 'user_aggregation',
      query: `
        SELECT
          user_id,
          COUNT(*) as transaction_count,
          SUM(CAST(amount AS FLOAT64)) as total_amount,
          AVG(CAST(amount AS FLOAT64)) as avg_amount,
          MIN(created_at) as first_activity,
          MAX(created_at) as last_activity,
          DATE_DIFF(DATE(MAX(created_at)), DATE(MIN(created_at)), DAY) as active_days_span,
          COUNT(DISTINCT DATE(created_at)) as active_days,
          COUNT(DISTINCT category) as categories_used
        FROM ${fullTableRef}
        WHERE DATE(created_at) BETWEEN '${startDate}' AND '${endDate}'
        GROUP BY user_id
        ORDER BY total_amount DESC
        LIMIT 1000000
      `
    });

    // User cohort analysis
    queries.push({
      name: 'user_cohort_analysis',
      query: `
        WITH user_first_activity AS (
          SELECT
            user_id,
            DATE_TRUNC(DATE(MIN(created_at)), MONTH) as cohort_month
          FROM ${fullTableRef}
          WHERE DATE(created_at) BETWEEN '${startDate}' AND '${endDate}'
          GROUP BY user_id
        )
        SELECT
          ufa.cohort_month,
          DATE_TRUNC(DATE(t.created_at), MONTH) as activity_month,
          DATE_DIFF(DATE_TRUNC(DATE(t.created_at), MONTH), ufa.cohort_month, MONTH) as months_since_first,
          COUNT(DISTINCT t.user_id) as active_users,
          COUNT(*) as total_transactions,
          SUM(CAST(t.amount AS FLOAT64)) as total_amount
        FROM ${fullTableRef} t
        JOIN user_first_activity ufa ON t.user_id = ufa.user_id
        WHERE DATE(t.created_at) BETWEEN '${startDate}' AND '${endDate}'
        GROUP BY cohort_month, activity_month, months_since_first
        ORDER BY cohort_month, months_since_first
      `
    });
  }

  if (aggregationType === 'full' || aggregationType === 'time_series') {
    // Hourly distribution analysis
    queries.push({
      name: 'hourly_distribution',
      query: `
        SELECT
          EXTRACT(HOUR FROM created_at) as hour_of_day,
          EXTRACT(DAYOFWEEK FROM created_at) as day_of_week,
          COUNT(*) as record_count,
          SUM(CAST(amount AS FLOAT64)) as total_amount,
          AVG(CAST(amount AS FLOAT64)) as avg_amount
        FROM ${fullTableRef}
        WHERE DATE(created_at) BETWEEN '${startDate}' AND '${endDate}'
        GROUP BY hour_of_day, day_of_week
        ORDER BY day_of_week, hour_of_day
      `
    });

    // Rolling averages
    queries.push({
      name: 'rolling_averages',
      query: `
        WITH daily_stats AS (
          SELECT
            DATE(created_at) as stat_date,
            COUNT(*) as daily_count,
            SUM(CAST(amount AS FLOAT64)) as daily_amount,
            AVG(CAST(amount AS FLOAT64)) as daily_avg
          FROM ${fullTableRef}
          WHERE DATE(created_at) BETWEEN '${startDate}' AND '${endDate}'
          GROUP BY stat_date
        )
        SELECT
          stat_date,
          daily_count,
          daily_amount,
          daily_avg,
          AVG(daily_count) OVER (ORDER BY stat_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) as rolling_7d_avg_count,
          AVG(daily_amount) OVER (ORDER BY stat_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) as rolling_7d_avg_amount,
          AVG(daily_count) OVER (ORDER BY stat_date ROWS BETWEEN 29 PRECEDING AND CURRENT ROW) as rolling_30d_avg_count,
          AVG(daily_amount) OVER (ORDER BY stat_date ROWS BETWEEN 29 PRECEDING AND CURRENT ROW) as rolling_30d_avg_amount,
          SUM(daily_count) OVER (ORDER BY stat_date) as cumulative_count,
          SUM(daily_amount) OVER (ORDER BY stat_date) as cumulative_amount
        FROM daily_stats
        ORDER BY stat_date
      `
    });
  }

  if (aggregationType === 'full') {
    // Anomaly detection via statistical analysis
    queries.push({
      name: 'anomaly_detection',
      query: `
        WITH daily_stats AS (
          SELECT
            DATE(created_at) as stat_date,
            COUNT(*) as daily_count,
            SUM(CAST(amount AS FLOAT64)) as daily_amount
          FROM ${fullTableRef}
          WHERE DATE(created_at) BETWEEN '${startDate}' AND '${endDate}'
          GROUP BY stat_date
        ),
        stats_with_bounds AS (
          SELECT
            *,
            AVG(daily_count) OVER (ORDER BY stat_date ROWS BETWEEN 30 PRECEDING AND 1 PRECEDING) as mean_count,
            STDDEV(daily_count) OVER (ORDER BY stat_date ROWS BETWEEN 30 PRECEDING AND 1 PRECEDING) as stddev_count,
            AVG(daily_amount) OVER (ORDER BY stat_date ROWS BETWEEN 30 PRECEDING AND 1 PRECEDING) as mean_amount,
            STDDEV(daily_amount) OVER (ORDER BY stat_date ROWS BETWEEN 30 PRECEDING AND 1 PRECEDING) as stddev_amount
          FROM daily_stats
        )
        SELECT
          stat_date,
          daily_count,
          daily_amount,
          mean_count,
          stddev_count,
          mean_amount,
          stddev_amount,
          CASE
            WHEN ABS(daily_count - mean_count) > 3 * stddev_count THEN 'HIGH'
            WHEN ABS(daily_count - mean_count) > 2 * stddev_count THEN 'MEDIUM'
            ELSE 'NORMAL'
          END as count_anomaly_level,
          CASE
            WHEN ABS(daily_amount - mean_amount) > 3 * stddev_amount THEN 'HIGH'
            WHEN ABS(daily_amount - mean_amount) > 2 * stddev_amount THEN 'MEDIUM'
            ELSE 'NORMAL'
          END as amount_anomaly_level
        FROM stats_with_bounds
        WHERE ABS(daily_count - mean_count) > 2 * stddev_count
           OR ABS(daily_amount - mean_amount) > 2 * stddev_amount
        ORDER BY stat_date
      `
    });

    // Data quality summary
    queries.push({
      name: 'data_quality_summary',
      query: `
        SELECT
          COUNT(*) as total_records,
          COUNTIF(user_id IS NULL) as null_user_ids,
          COUNTIF(amount IS NULL) as null_amounts,
          COUNTIF(category IS NULL) as null_categories,
          COUNTIF(created_at IS NULL) as null_timestamps,
          COUNTIF(SAFE_CAST(amount AS FLOAT64) IS NULL AND amount IS NOT NULL) as invalid_amounts,
          COUNT(DISTINCT user_id) as unique_users,
          COUNT(DISTINCT category) as unique_categories,
          MIN(created_at) as earliest_record,
          MAX(created_at) as latest_record,
          ROUND(COUNTIF(user_id IS NULL) * 100.0 / COUNT(*), 2) as pct_null_user_ids,
          ROUND(COUNTIF(amount IS NULL) * 100.0 / COUNT(*), 2) as pct_null_amounts
        FROM ${fullTableRef}
        WHERE DATE(created_at) BETWEEN '${startDate}' AND '${endDate}'
      `
    });
  }

  return queries;
}

module.exports = { processLargeDataset: functions.http };